class AckPolicy(enum.Enum):
    
    EXPLICIT = 0
    
    AUTOMATIC = 1
    


class _UniffiFfiConverterTypeAckPolicy(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return AckPolicy.EXPLICIT
        if variant == 2:
            return AckPolicy.AUTOMATIC
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == AckPolicy.EXPLICIT:
            return
        if value == AckPolicy.AUTOMATIC:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == AckPolicy.EXPLICIT:
            buf.write_i32(1)
        if value == AckPolicy.AUTOMATIC:
            buf.write_i32(2)





# AckedError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class AckedError(Exception):
    pass

_UniffiTempAckedError = AckedError

class AckedError:  # type: ignore
    
    class AckedError(_UniffiTempAckedError):
        def __repr__(self):
            return "AckedError.AckedError({})".format(repr(str(self)))
    _UniffiTempAckedError.AckedError = AckedError # type: ignore

AckedError = _UniffiTempAckedError # type: ignore
del _UniffiTempAckedError


class _UniffiFfiConverterTypeAckedError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return AckedError.AckedError(
                _UniffiFfiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, AckedError.AckedError):
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, AckedError.AckedError):
            buf.write_i32(1)



